package ru.memearena.security; import org.springframework.stereotype.Component; import java.nio.charset.StandardCharsets; import java.security.*; import java.util.*;
@Component public class TokenService { private final SecureRandom random=new SecureRandom(); public String generate(){byte[] b=new byte[32]; random.nextBytes(b); return Base64.getUrlEncoder().withoutPadding().encodeToString(b);} public String sha256(String raw){try{var md=MessageDigest.getInstance("SHA-256"); byte[] d=md.digest(raw.getBytes(StandardCharsets.UTF_8)); var sb=new StringBuilder(); for(byte x:d) sb.append(String.format("%02x",x)); return sb.toString();}catch(Exception e){throw new IllegalStateException(e);}} public boolean constantEquals(String a,String b){byte[] x=a==null?new byte[0]:a.getBytes(StandardCharsets.UTF_8), y=b==null?new byte[0]:b.getBytes(StandardCharsets.UTF_8); return MessageDigest.isEqual(x,y);} }
